import React, { useState, useEffect } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';  // Подключение стилей Bootstrap
import { BrowserRouter as Router, Route, Switch, Link } from 'react-router-dom';
import EventList from './EventList';  // Импорт компонента с мероприятиями
import LoginPage from './LoginPage';  // Импорт компонента страницы авторизации
import { useHistory } from 'react-router-dom';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const history = useHistory();

  // Проверка авторизации при загрузке приложения
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      setIsAuthenticated(true);
    }
  }, []);

  // Функция для выхода
  const handleLogout = () => {
    localStorage.removeItem('token');  // Удаляем токен из localStorage
    setIsAuthenticated(false);  // Меняем состояние авторизации
    history.push('/login');  // Перенаправляем на страницу авторизации
  };

  return (
    <div className="App">
      <Router>
        {/* Навигационная панель */}
        <nav className="navbar navbar-expand-lg navbar-dark bg-primary">
          <a className="navbar-brand" href="#">Организация Мероприятий</a>
          <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav" aria-controls="navbarNav" aria-expanded="false" aria-label="Toggle navigation">
            <span className="navbar-toggler-icon"></span>
          </button>
          <div className="collapse navbar-collapse" id="navbarNav">
            <ul className="navbar-nav">
              <li className="nav-item active">
                <Link className="nav-link" to="/">Главная</Link>
              </li>
              <li className="nav-item">
                <Link className="nav-link" to="/events">Мероприятия</Link>
              </li>
              {!isAuthenticated ? (
                <li className="nav-item">
                  <Link className="nav-link" to="/login">Войти</Link>
                </li>
              ) : (
                <li className="nav-item">
                  <button className="btn btn-danger" onClick={handleLogout}>Выйти</button>
                </li>
              )}
            </ul>
          </div>
        </nav>

        {/* Маршруты */}
        <Switch>
          <Route path="/login" component={LoginPage} />
          <Route path="/events" render={() => isAuthenticated ? <EventList /> : <LoginPage />} />
          <Route path="/" exact render={() => isAuthenticated ? <EventList /> : <LoginPage />} />
        </Switch>
      </Router>
    </div>
  );
}

export default App;
